interface Item {
  nome: string;
  quantidade: number;
  valor: number;
}

const inventario: Item[] = [
  { nome: "Poção", quantidade: 5, valor: 10 },
  { nome: "Espada", quantidade: 1, valor: 150 },
  { nome: "Flecha", quantidade: 20, valor: 2 }
];

let total: number = 0;
for (const item of inventario) {
  total += item.quantidade * item.valor;
}
console.log(`Valor total: ${total}`);

